import psycopg2

def connect():
    connection = psycopg2.connect(
        host="your_host",
        database="your_database",
        user="your_user",
        password="your_password"
    )
    return connection

def search_users(username=None, email=None, role=None, status=None, connection=None):
    cursor = connection.cursor()

    query = """
        SELECT * FROM users
        WHERE 1=1
    """

    params = {}

    if username:
        query += " AND username=%s"
        params["username"] = username

    if email:
        query += " AND email=%s"
        params["email"] = email

    if role:
        query += " AND role=%s"
        params["role"] = role

    if status:
        query += " AND account_status=%s"
        params["status"] = status

    cursor.execute(query, list(params.values()))
    result = cursor.fetchall()

    cursor.close()
    return result

connection = connect()
results = search_users(username='john', role='admin', status='active')
print(results)